addEventListener('fetch', event => {
  event.respondWith(handle(event.request))
})

async function handle(req) {
  // Simple token-bucket style rate limit using Workers KV (illustrative)
  const ip = req.headers.get('cf-connecting-ip') || 'anon'
  const key = `rl:${ip}`
  const now = Date.now()
  // get remaining tokens and last timestamp
  const state = JSON.parse((await RATE_KV.get(key)) || '{"tokens": 10, "ts": 0}')
  const refillRate = 1 // token per second
  const maxTokens = 10
  const elapsed = Math.max(0, Math.floor((now - state.ts) / 1000))
  let tokens = Math.min(maxTokens, state.tokens + (elapsed * refillRate))
  if (tokens < 1) {
    return new Response('Too Many Requests', { status: 429 })
  }
  tokens -= 1
  await RATE_KV.put(key, JSON.stringify({ tokens, ts: now }))
  return fetch(req)
}
